import{_ as a,o as l,c as t,ae as i}from"./chunks/framework.Dg21OTSi.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"note/我的项目/面试辅导.md","filePath":"note/我的项目/面试辅导.md"}'),o={name:"note/我的项目/面试辅导.md"};function p(r,e,n,_,s,d){return l(),t("div",null,[...e[0]||(e[0]=[i('<h2 id="考微前端主要考什么" tabindex="-1">考微前端主要考什么？ <a class="header-anchor" href="#考微前端主要考什么" aria-label="Permalink to &quot;考微前端主要考什么？&quot;">​</a></h2><h2 id="项目先后顺序怎么放" tabindex="-1">项目先后顺序怎么放？ <a class="header-anchor" href="#项目先后顺序怎么放" aria-label="Permalink to &quot;项目先后顺序怎么放？&quot;">​</a></h2><p>再加几个和 AI 相关的技能就可以，比如说：</p><ol><li>使用 Skill 提升你们的测试覆盖率</li><li>进行 v2 到 v3 的一个升级</li><li>进行 code review</li></ol><p>Code review 可以往前边写一些，然后再写一些掌握的 AI 技能。</p><p>比如：</p><ol><li>Skills</li><li>Agents.md</li><li>如何正确并且高效地创建 plan</li></ol><p>把这些都写在技能里边</p><p>前端有一些工具函数（比如日期函数，还有像 Lodash 那样的一些工具函数），这些都可以做很好的单测，而且覆盖率要求会比较高，基本上每个都要覆盖到。</p><p>然后是组件测试。这种测试主要是针对 Vue 组件，看它是否正确渲染、每个分支是否覆盖。这部分目前写得比较少。</p><p>还有一个是端对端（E2E）测试，可以针对重点逻辑和重点流程来做。</p><p>我觉得测试重点应该是“抓两头”：</p><ol><li>工具函数：需要全部覆盖</li><li>端对端测试：覆盖重要流程</li></ol><p>对于中间的那些组件，我觉得能写就写吧。</p><p>面试的时候就看你怎么说，你也可以说：你在早期先把它（项目）的工具函数以及所有的重要流程都做了端到端测试，然后再重构成 Vue3；发现所有端到端测试都通过后，再手动测试一下其他组件和页面，接着交给测试或者其他同事去测一下。没有问题的话，最后就验收通过。</p><p>面试官有可能会对这个环节提问，你可以找一个小项目提前做下准备。</p>',16)])])}const m=a(o,[["render",p]]);export{h as __pageData,m as default};
